"""
Standalone patch — writes mkt-context for Isaiah 33-36.
Run: python3 scripts/zc-context-isaiah-33-36-patch.py
Chapters: 33 (24v), 34 (17v), 35 (10v), 36 (22v) = 73 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "33": {
    "1": "<p>Isaiah 33:1 opens the sixth and final woe of the woe-series (28:1; 29:1, 15; 30:1; 31:1; 33:1), now directed not at Judah but at the unnamed destroyer: 'hoi shoded velo shudad uboghed lo bagad bo, woe to you destroyer who has not been destroyed, betrayer who has not been betrayed.' The unidentified destroyer is almost certainly Assyria — the empire that has devastated nation after nation without itself facing reciprocal destruction. The antiphonic structure: shaded/shudad (destroyer/destroyed) and boghed/bugad (betrayer/betrayed) — four words sharing the same consonantal frame, the action and its reversal. 'When you finish destroying, you yourself will be destroyed' (kikallotekha shadod tushad, when you complete destroying, you will be destroyed) — divine justice operates on the lex talionis of cosmic proportion: the destroyer receives the full measure he gave.</p>",
    "2": "<p>'LORD, be gracious to us; we wait for you. Be our arm of strength every morning, our salvation in the time of trouble' — the community prayer that follows the pronouncement of judgment on the destroyer. 'YHWH channenu lekha qivvinu, LORD be gracious to us; we wait/hope for you.' The qivvah (waiting/hoping) is the signature posture of the faithful remnant throughout the Isaiah Apocalypse (25:9; 26:8; 30:18). 'Their arm every morning' (zero'am labbeqarim, be our arm in the mornings) — 'our arm' here is a reversal of 40:10 ('his mighty arm will rule for him'); YHWH acts as the people's arm, their instrument of strength. 'Every morning' (labbeqarim, in the mornings) = the daily renewal of divine protection, each morning a new act of grace. 'Our salvation in the time of trouble' (af-yeshu'atenu be'et tsarah, also our salvation in the time of distress) = the Ps 46:1 vocabulary: 'God is our refuge and strength, an ever-present help in trouble.'</p>",
    "3": "<p>'At the uproar of your voice the peoples flee; when you rise up, the nations scatter' — the divine-warrior battle-cry: 'miqqol hammon neddu ammim, at the sound of the tumult/uproar the peoples fled.' The hmom (tumult/uproar = the divine battle-roar, the same as the 'roar of many waters' in 17:12-13) scattered the nations (amm). 'Miroom'ekha yippotsetshu goyim, when you arise the nations will be scattered' (yippotsetshu from puts = to scatter/be dispersed). The imagery: YHWH 'rising up' (romem, the exaltation of the king to his throne in battle) triggers the enemy's flight. This is the divine-warrior language of Ps 68:1: 'May God arise, may his enemies be scattered; may his foes flee before him.'</p>",
    "4": "<p>'Your spoil will be gathered as the locust swarm strips a field; like grasshoppers leaping on it, people will rush over it' — the reversal of Assyrian plunder: 've'usaf shalalkhem aseph hechasiyl, your spoil will be gathered as the locust gathers.' The heChaSiyl (the species-of-locust = the devouring locust that strips everything) and arbeh (the swarming locust/grasshopper = the locust in its mature swarming stage, the same arbeh as Exod 10:4-19's plague of locusts). The Assyrian army that came to plunder Judah (like a locust swarm, consuming everything) has its own plunder stripped away like a field after a locust swarm. The locust-like speed: 'mishaq hashaq bo, like grasshoppers leaping upon it, men will rush over it.' The counter-plundering is as swift and thorough as the original Assyrian devastation.</p>",
    "5": "<p>'The LORD is exalted, for he dwells on high; he has filled Zion with justice and righteousness' — the declaration of YHWH's enthronement after the enemy's defeat: 'nisgav YHWH ki shokhen marom, exalted is YHWH for he dwells on high.' Nisgav (from sagav = to be high/lofty/inaccessible — the same root as 2:11's bringing low what is lofty: YHWH's exaltation is the obverse of the proud's humiliation). 'He has filled Zion with justice and righteousness' (mille Tsiyon mishpat utsedaqah, he has filled Zion with justice and righteousness). The filling of Zion with mishpat and tsedaqah echoes 1:21-27 (the restoration of Zion as 'City of Righteousness') and 32:1 (the messianic king who reigns in righteousness). The defeat of the enemy produces the filling of Zion with YHWH's covenant attributes.</p>",
    "6": "<p>'He will be the stability of your times — an abundance of salvation, wisdom, and knowledge; the fear of the LORD is his treasure' — the six attributes of the messianic era: 'vehayah emunath ittekha, and he will be the faithfulness of your times.' Emunath (faithfulness/stability, from aman = to be firm/reliable = the root of 'Amen') = YHWH as the reliable foundation of the era. 'An abundance of salvation, wisdom, and knowledge' (cheshen yeshuot, chokhmah, vada'at, riches of salvation, wisdom, and knowledge). The three wisdom-attributes: yeshuot (salvations/deliverances), chokhmah (wisdom = the practical skill of right living), da'at (knowledge = the covenant-intimacy of relationship with YHWH). 'The fear of the LORD is his treasure' (yirat YHWH hi' otsaro, the fear of YHWH is his treasure) — the fear-of-YHWH as the supreme wealth (Prov 1:7: 'the fear of the LORD is the beginning of wisdom'; Job 28:28: 'the fear of the Lord — that is wisdom').</p>",
    "7": "<p>'Look — their brave warriors cry out in the streets; the envoys of peace are weeping bitterly' — the crisis scene before YHWH's decisive intervention: 'hen er'elam tsa'aqah chutsa, look, the arielim cry out in the street.' The erielam (their arielim = the 'lions of God' = the heroes, the same Ariel-root as Jerusalem in 29:1) = the bravest warriors. Even the mighty warriors are crying out (tsa'aqah, the desperate cry for help). 'The envoys of peace weep bitterly' (malachey shalom mar yivkayun, the messengers of peace weep bitterly) — the diplomatic corps sent to negotiate peace (the envoys to Assyria, or perhaps Sennacherib's own peace-terms envoys) now weeping. The failed negotiations: the 'envoys of peace' = Hezekiah's delegation or the Assyrian negotiators whose terms were refused.</p>",
    "8": "<p>'The highways are desolate, all travel has ceased; he has broken the covenant, he has despised the cities, he has no regard for human life' — the breakdown of civilization under Assyrian pressure: 'nashammu mesillot, the highways are desolate.' The mesillot (raised highways/main roads) = the arterial infrastructure of commerce and communication. 'Travel has ceased' (shavat over orach, the wayfarer/traveler has ceased) — commerce, pilgrimage, and communication all stopped. 'He has broken the covenant' (hefir berit, he has annulled the covenant) = the ANE suzerainty treaty violation: Assyria's protocol included sworn treaties with vassal states, and breaking these oaths was a capital offense under ANE law (cf. Ezek 17:15-19 on the covenant-breaking of a king who went to Egypt for help). 'No regard for human life' (lo chashav enosh, he has not valued a human being) = the Assyrian dehumanization of defeated populations.</p>",
    "9": "<p>'The earth mourns and fades; Lebanon withers in shame; the Sharon plain is like a desert; Bashan and Carmel are stripping off their leaves' — the mourning of the great fertile landscapes: 'aval umlelah erets, the earth mourns and languishes' (the same pair as 24:4 in the Isaiah Apocalypse). The four geographic symbols of the land's fertility: Lebanon (the cedar forests of the north = the symbol of majestic natural beauty, 1 Kgs 5:6-10; Ps 92:12); the Sharon plain (the coastal plain between Carmel and Joppa = the fertile grain-growing region of the coastal plain; Isa 35:2 reverses this); Bashan (the rich pasturelands east of the Sea of Galilee = the prime cattle-grazing region, Ps 22:12; Amos 4:1); Carmel (the garden-mountain of the north coast, the same Carmel as Elijah's contest in 1 Kgs 18). All four 'stripping their leaves' = the comprehensive ecological mourning before YHWH's intervention.</p>",
    "10": "<p>'Now I will rise, declares the LORD; now I will be exalted; now I will be lifted up' — the divine first-person declaration of decisive action: 'attah aqum, now I will rise.' Three synonymous verbs of divine exaltation: aqum (I will rise = the posture of the warrior/judge standing for action), aromam (I will exalt myself = raise myself to full height), etnaase (I will be lifted up = the technical word for the royal elevation, the same word as the 'lifted up' of 6:1: 'I saw the LORD seated on a throne, high and lifted up'). The triple 'now' (attah...attah...attah) = the urgency and decisiveness of the moment. After the mourning of vv.7-9, YHWH's standing up is the pivot point of the chapter.</p>",
    "11": "<p>'You conceive chaff; you give birth to stubble; your own breath, like fire, will consume you' — the Assyrian's self-destruction by their own schemes: 'tagru chashash teledhu kash, you conceive chaff, you give birth to stubble.' The biological metaphor of pregnancy applied to their schemes: what they conceived (the plan to destroy Judah) is chaff (chashash = the light chaff of threshing) and what they give birth to is kash (stubble = the dry stalks after harvest, equally worthless). 'Your own breath, like fire, will consume you' (ruchakem esh tokkelkhem, your own spirit/breath, fire, will eat you) — the Assyrian's own power (their ruach = their spirit/breath/military force) will be the fire that destroys them. The self-consuming fire of judgment: they are burned by their own breath. Cf. 30:33: the breath of YHWH kindles the Topheth fire.</p>",
    "12": "<p>'The peoples will be burned like limestone; like cut thornbushes they will be set ablaze in the fire' — the comprehensive burning of the enemy: 'vehayu ammim misrefot sid, and peoples will be burnings of lime' (misrefot sid = lime-burnings = the process of burning limestone to produce quicklime). The burning of limestone: limestone was heated in kilns to produce quicklime (calcium oxide), used as mortar and whitewash. The process required sustained intense heat until the stone was completely consumed. 'Like cut thornbushes set ablaze in fire' (kemotsats kotsim baesh yitsatsetshu, like the cutting of thorns, in fire they will burn each other). The thornbush-fire = the same thorns-and-briers judgment-vegetation (9:18: 'thorns and briers will be set on fire') burning rapidly and completely. Both images: complete, quick consumption leaving nothing.</p>",
    "13": "<p>'Hear, you who are far away, what I have done; and you who are near, acknowledge my power' — the universal proclamation after the defeat of the enemy: 'shime'u rechoqim asher asiti, hear, O far-away ones, what I have done.' The 'far away' (rechoqim) and 'near' (qerovim) together = the full geographic scope of YHWH's audience. This is the proclamation to the nations of what YHWH did at Zion — the Sennacherib crisis becomes a demonstration of divine power for the entire world. 'Acknowledge my power' (de'u gevurati, know/acknowledge my might) — yada (know/acknowledge) as the recognition formula: the nations will come to know YHWH through his demonstration of power. Ezek 36-39 uses the same 'then they will know that I am YHWH' formula 50+ times.</p>",
    "14": "<p>'The sinners in Zion are terrified; trembling has seized the godless: Who among us can live with the devouring fire? Who among us can dwell in perpetual flames?' — the terror of sinners before the holy God enthroned in Zion: 'pachadu beTsiyon chatta'im, in Zion the sinners are terrified' — the same Zion that is the refuge of the righteous is the place of terror for the sinners within it. The two questions: 'mi yagur lanu esh okhelah? mi yagur lanu moqdei olam? who can dwell with devouring fire? who can dwell with everlasting flames?' The 'devouring fire' (esh okhelah) and 'everlasting flames' (moqdei olam) = YHWH himself, who is a 'consuming fire' (Deut 4:24; 9:3; Heb 12:29: 'our God is a consuming fire'). The theological problem of the holy God dwelling in Zion: his holiness consumes. The answer (vv.15-16) is the entrance liturgy — the righteous character that can approach the Holy One.</p>",
    "15": "<p>'The one who walks righteously and speaks honestly, who refuses unjust gain, who shakes his hands free of bribes, who stops his ears from plots of bloodshed, and shuts his eyes from looking on evil' — the entrance liturgy answering 'who can dwell with the devouring fire?' Six righteous qualities: (1) 'holek tsedaqot, walking righteously' (lifestyle); (2) 'dover mesharim, speaking uprightly' (speech); (3) 'mo'es bevetsa maashaquot, rejecting unjust gain' (economic integrity); (4) 'no'er kappaiv mittmokh bashochad, shaking his hands from holding bribes' (judicial integrity — the bribe falling from the palm like a rejected object); (5) 'ottem ozno mishmoa damim, stopping his ear from hearing blood-plots' (refusal to participate in murderous scheming); (6) 'ottsem einaiv mer'ot bera, shutting his eyes from seeing evil' (deliberate avoidance of evil). Psalm 15 and 24:3-6 are the closest parallel entrance-liturgies: 'Who may ascend the mountain of the LORD? Who may stand in his holy place? The one who has clean hands and a pure heart...'</p>",
    "16": "<p>'That person will dwell on the heights; his refuge will be a fortress of rocks. His bread will be provided; his water will be reliable' — the reward of the righteous character described in v.15: 'hu meromim yishkon, he will dwell in the heights' (meromim = the high places = the place of YHWH's dwelling, 33:5: YHWH dwells on high). The righteous person inhabits the same heights as YHWH himself — access to the divine presence is the supreme privilege. 'His refuge will be a fortress of rocks' (misgav sela'im mesado, a stronghold of rocks is his refuge) = the rock-fortress imagery of Ps 18:2 and 27:5: 'In the day of trouble he will keep me safe in his dwelling; he will hide me in the shelter of his sacred tent.' 'His bread will be provided' (lachmo nitan, his bread will be given) — divine provision for daily needs. 'His water will be reliable' (meimav ne'emanim, his waters are faithful/trustworthy) — the covenant-faithfulness attribute (ne'eman from aman = reliable) applied to water supply.</p>",
    "17": "<p>'Your eyes will see the king in his beauty; they will look out over a land that stretches far away' — the eschatological vision of the messianic king: 'melek beyofyo tir'einah einekha, a king in his beauty your eyes will see.' The melek beyofyo (a king in his beauty = the ideal king of 32:1 who reigns in righteousness, now seen in the fullness of his beauty). This is the vision promised to the righteous person who can 'dwell on the heights' (v.16) — they see the king directly. 'They will look out over a land that stretches far away' (tir'einah erets merhaqim, they will see a land of far distances) = the full extent of the promised land, without the limitation of siege or Assyrian occupation. The contrast: during the Assyrian crisis, the king was in distress and the land was besieged; now the king is beautiful and the land is expansive.</p>",
    "18": "<p>'Your heart will recall the terror: Where is the scribe? Where is the one who tallied the tribute? Where is the one who counted the towers?' — the post-crisis memory of the Assyrian bureaucracy: 'libbekha yehgeh emah, your heart will meditate on the terror.' The recalling of the Assyrian administrative apparatus that managed conquered territories: 'where is the scribe?' (sofer = the Assyrian accountant/tax assessor who calculated tribute) — documented in Assyrian annals as the first administrative step after conquest; 'where is the one who weighed?' (shoqel = the one who weighed tribute in silver — the Assyrian system of exacting tribute by weight of precious metals); 'where is the one who counted the towers?' (sofer et-hamigdalim = the military engineer who surveyed the city's defenses to plan the siege). All three are gone — the terrifying Assyrian bureaucracy that preceded conquest has been removed. The memory of terror heightens the joy of deliverance.</p>",
    "19": "<p>'You will no longer see that fierce people — a people of speech too deep to make out, of a strange tongue that you cannot understand' — the removal of the incomprehensible enemy: 'et-am noz lo tir'eh, the fierce people you will not see anymore.' The am noz (the fierce/bold people = the Assyrian army; noz from nuz = to flee/be bold?) — no longer visible on Judah's horizon. 'A people of speech too deep to make out' (am ammoq safah, a people deep of lip = whose speech is too deep/difficult to fathom). 'Of a strange tongue that you cannot understand' (nilaz lashon ein bina, of a derided/stammering tongue, without understanding). The incomprehensible Assyrian speech (already referenced in 28:11: 'by people of strange lips and a foreign tongue') that served as judgment (1 Cor 14:21) is now gone. The community is no longer subjected to the terrifying foreign-language demands of conquerors.</p>",
    "20": "<p>'Look upon Zion, the city of our appointed festivals! Your eyes will see Jerusalem — a dwelling at peace, a tent that will never be taken down, whose stakes will never be pulled up, and none of whose ropes will ever be broken' — the permanent Zion tent: 'chazeh Tsiyon qiryat moadenu, look upon Zion, the city of our appointed assemblies.' The moadenu (our appointed times = the three annual pilgrimage festivals of Exod 23:14-17: Passover, Weeks/Shavuot, Tabernacles/Sukkot). Jerusalem as the festival city — the place to which all Israel gathered for covenant renewal. 'A tent that will never be taken down' (ohel bilthi-yen, a tent that will not be lifted/removed) — the Tabernacle/tent imagery applied to Jerusalem: the city is like the Tabernacle (the mobile sanctuary of the wilderness) but now permanent. The three covenant-permanence markers: stakes never pulled up, ropes never broken = the impermanent tent becomes permanently established.</p>",
    "21": "<p>'But there the LORD in his glory will be for us a place of broad rivers and streams — where no warship with oars will sail and no mighty vessel will pass through' — YHWH as the city's waterway: 'ki im-sham adir YHWH lanu, for there the majestic YHWH will be for us.' YHWH himself is the 'broad rivers and streams' (yeor rechav yadaim, the broad rivers, wide of hands = the wide, many-channeled rivers). Jerusalem had no significant river — the Kidron was a seasonal wadi. YHWH's presence substitutes for the strategic advantage of river-based cities (Babylon on the Euphrates; Nineveh on the Tigris; Thebes on the Nile). 'Where no warship with oars will sail' (lo-telek bo oniyet shayyit, a vessel of oars will not go there) — the absence of enemy fleets despite being on 'rivers.' YHWH's rivers have the strategic advantage of rivers without the vulnerability to naval attack.</p>",
    "22": "<p>'For the LORD is our judge, the LORD is our lawgiver, the LORD is our king — he will save us' — the triple divine governance declaration: 'ki YHWH shofetenu, for YHWH is our judge.' Three constitutional roles of ancient governance (judge, lawgiver, king) all collapsed into YHWH alone: shofetenu (our judge = the judicial role, as in the time of the judges before the monarchy); mechqqenu (our lawgiver = the legislative role, from chaqaq = to engrave/decree); malkenu (our king = the executive/military role). The three functions that human institutions divided between judges, scribes, and monarchs are reunified in YHWH. 'He will save us' (hu yoshiene, he will save us) — the three-role declaration ends in simple salvation. This echoes the Shema theology: YHWH alone is Israel's true ruler, and his rule produces salvation.</p>",
    "23": "<p>'Your rigging hangs slack; the mast cannot be steadied; no sail can be spread. Then a great plunder will be divided — even the lame will carry off their share of the spoil' — the ship-metaphor applied to the enemy: 'nitashu chaveyleikh, your ropes hang slack' (chaveyleikh = your ropes/rigging). The ship under divine judgment: the mast unstable, the sail unable to spread = a vessel completely disabled. Then the reversal: 'az challaq shallal marbeh, then a great plunder will be divided.' The disabled enemy ship is plundered — and even 'the lame will carry off their share of the spoil' (pissechim yivozzu baz, the lame/crippled will divide the plunder). The lame plundering enemy soldiers is the extreme reversal of conventional military logic — the most vulnerable members of the covenant community participate in the victory-plunder. 2 Sam 5:8 records David's original slur: 'The blind and lame will not enter the palace' — now the lame carry the plunder.</p>",
    "24": "<p>'And no inhabitant will say, I am sick; the people who dwell there will have their iniquity forgiven' — the twin blessings of the eschatological Zion: (1) 'velo yomar shaken chaliti, no inhabitant will say, I am sick.' The cessation of illness = the healing of the community that was spiritually sick (1:5-6: 'the whole head is sick, the whole heart faint; from the sole of your foot to the top of your head there is no soundness'). The eschatological community is physically and spiritually whole. (2) 'Ha'am hayoshev bah nessa avono, the people dwelling there will have their iniquity carried/forgiven' — nessa (from nasa = to lift up/carry away = the standard forgiveness-vocabulary: Gen 50:17; Exod 10:17; Num 14:19; Mic 7:18: 'Who is a God like you, who pardons sin and forgives?'). The comprehensive restoration: no sickness and no unforgiven sin. Rev 21:4 and 22:3 complete this: no more death, mourning, crying, pain, no more curse.</p>"
  },
  "34": {
    "1": "<p>'Come near, O nations, and hear! Listen, O peoples! Let the earth hear and everything in it — the world and all that springs from it' — the universal summons to witness divine judgment: 'qirveu goyim lishmo'a, draw near, O nations, to hear.' The court-summons formula (Ps 50:1: 'the Mighty One, God the LORD, speaks and summons the earth from the rising of the sun to where it sets'). All four are summoned to hear: goyim (nations), ammim (peoples), erets (earth), and melo'ah (its fullness = everything on earth, cf. Ps 24:1: 'the earth is the LORD's and everything in it'). The comprehensive summons parallels the beginning of major covenant lawsuits (Deut 32:1: 'Listen, you heavens, and I will speak; hear, you earth, the words of my mouth'). Isaiah 34-35 forms a bookend pair: ch.34 = judgment on the nations/Edom; ch.35 = restoration of Israel.</p>",
    "2": "<p>'For the LORD is enraged against all the nations and furious against all their armies; he has devoted them to destruction and given them over to slaughter' — the universal scope of divine wrath: 'ki qetsaf YHWH al-kol-hagoyim, for YHWH is enraged against all the nations.' The qetsef (fury/rage = the intense anger that burns like fire) 'against all the nations' (kol-hagoyim) = the comprehensive judgment of the Isaiah Apocalypse (chs.13-23 judged the nations individually; here the entire category is condemned). 'He has devoted them to destruction' (vehechariym otam, he has devoted them to the ban/herem) — the herem (sacred destruction = the complete dedication of defeated enemies to YHWH through total annihilation, the same vocabulary as Josh 6:17-21's Jericho and Deut 7:2's Canaanite-conquest commands). The war-ban applied to all nations = cosmic holy war.</p>",
    "3": "<p>'Their slain will be cast out, and the stench of their corpses will rise; the mountains will be soaked with their blood' — the aftermath of cosmic judgment: 'vechalleleyhem yushlaku, their slain will be cast out.' The casting out of the unburied dead = the ultimate dishonor in the ANE; denial of burial was a severe curse (Deut 28:26: 'your carcasses will be food for all the birds and the wild animals'). 'The stench of their corpses will rise' (mippigereiyhem ya'aleh ba'asham, from their corpses their stench will go up). 'The mountains will be soaked with their blood' (venimassu harim middamam, the mountains will melt with their blood) — rivers of blood soaking the mountains = the scale of cosmic judgment exceeding any historical battle. This hyperbolic intensity signals the eschatological scope: not a single battle but the final settling of all accounts.</p>",
    "4": "<p>'All the host of heaven will dissolve; the heavens will be rolled up like a scroll. All their host will fall down as a leaf falls from a vine, or as a fig drops from a fig tree' — the dissolution of the cosmic order: 'venimqahu kol-tseva hashamayim, and all the host of heaven will dissolve/rot.' The tseva hashamayim (host of heaven = the sun, moon, and stars — and perhaps the angelic powers behind the nations, cf. 24:21). 'Venikpelu kassefer hashamayim, and the heavens will be rolled up like a scroll' — the scroll-metaphor for heaven: the sky rolled up like a papyrus or parchment scroll being closed. Rev 6:14 quotes this directly: 'The heavens receded like a scroll being rolled up.' The falling host: 'as a leaf falls from a vine' (kenibol aleh miggefen) and 'as a fig drops from a fig tree' (ukhinbol mitte'enah = the autumn fig that falls with the slightest touch when fully ripe). The immense stars/powers fall as easily as dead leaves.</p>",
    "5": "<p>'For my sword has been bathed in heaven; see — it descends on Edom, on the people I have devoted to destruction, for judgment' — the sword of divine judgment specifically targeting Edom: 'ki rivetah beshamayim charbi, for my sword has been saturated/watered in the heavens.' The divine sword 'watered' (riva, from ravah = to drink one's fill, to be saturated with blood) in heaven before its earthly descent — the judgment prepared in heaven before it lands on earth. 'See — it descends on Edom' (hineh al-edom terade, behold it will descend on Edom). Edom (the descendants of Esau, dwelling south and east of the Dead Sea) is the paradigmatic enemy of Israel: Gen 25-36 (Jacob and Esau's enmity); Ps 137:7 ('Remember, LORD, what the Edomites did on the day Jerusalem fell'); Obadiah (the entire book against Edom). 'The people I have devoted to destruction, for judgment' (ve'al-am chirmi lemishpat, and on the people of my ban/herem for judgment).</p>",
    "6": "<p>'The sword of the LORD is filled with blood; it is gorged with fat — the blood of lambs and goats, the fat of rams' kidneys. For the LORD has a sacrifice in Bozrah, a great slaughter in the land of Edom' — the sacrifice metaphor for divine judgment: 'cherev laYHWH male'ah dam, the sword of YHWH is full of blood.' The military judgment described as a sacrificial meal: 'filled with fat' (huddeshenah mechelev, saturated with fat) — the blood and fat are the parts of the sacrifice that belong to YHWH (Lev 3:16-17: 'all the fat is the LORD's'; 17:6). The animals listed are sacrificial animals: lambs (kevasim), goats (attudim), rams (ayilim) — the precise vocabulary of the peace-offering. 'The LORD has a sacrifice in Bozrah' (ki zevach laYHWH beBosra, for YHWH has a sacrifice in Bozrah) — Bozrah (modern Buseirah in Jordan, the Edomite capital city) is the slaughter-site. Rev 19:17-18 and Ezek 39:17-20 develop the 'great supper/sacrifice' motif of divine judgment.</p>",
    "7": "<p>'Wild oxen will fall with them, young bulls together with mighty bulls; their land will be soaked with blood, and their soil made rich with fat' — the extension of the sacrifice-imagery to wild animals: 'veyerdu remmim imam, and wild oxen will come down with them.' The re'em (the wild ox/aurochs — the most powerful wild bovine of the ANE, Job 39:9-12; Num 23:22; Deut 33:17 — 'the strength of a wild ox') alongside the domesticated bulls (parim ve'abbirim, young bulls and great bulls). The full spectrum of bovine power (wild to domestic, young to mature) all sacrificed. 'Their land will be soaked with blood' (vesirvetah artsam middamam, their land will be drunk with blood) and 'their soil made rich with fat' (vafaras adamatam mechalev, their soil will be saturated/made fat with fat) — the soil itself enriched by the divine sacrifice, as field soil is fertilized by organic matter.</p>",
    "8": "<p>'For the LORD has a day of vengeance, a year of recompense for the cause of Zion' — the theological grounding of Edom's judgment: 'ki yom naqam laYHWH, for it is a day of vengeance for YHWH.' The naqam (vengeance = the righteous vindication of wrong done to a covenant party, the same naqam as 'vengeance is mine, I will repay, says the Lord' in Deut 32:35; Rom 12:19; Heb 10:30). 'A year of recompense for the cause of Zion' (shnat shillumim leryv Tsiyon, a year of recompense for the dispute/legal cause of Zion). The legal terminology: Zion's legal case (riv = lawsuit/dispute) against Edom is being settled by divine recompense (shillumim = retribution/payment). Edom's cruelty at Jerusalem's fall (Ps 137:7; Obad 11-14) is the specific cause being repaid. Isa 61:2 quotes the same 'day of vengeance of our God' in the Spirit-anointed servant's proclamation.</p>",
    "9": "<p>'The streams of Edom will be turned to tar, its soil to sulfur, and its land will become burning pitch' — Sodom applied to Edom: 'vehafkhu nechaleiha lezefet, and its streams will be turned to tar/pitch.' The three substances: zefet (tar/pitch = the bituminous material of the Dead Sea region, Gen 14:10: the Valley of Siddim full of tar pits), gofrit (sulfur = the burning sulfite of Gen 19:24: 'YHWH rained down burning sulfur on Sodom and Gomorrah'), and yit-bahm (burning pitch = the self-sustaining fire). Sodom and Gomorrah (Gen 19) were destroyed by fire and sulfur from heaven — the most comprehensive divine judgment in the OT. By using the same vocabulary for Edom, Isaiah applies the Sodom-judgment to Edom. Edom's territory (south of the Dead Sea) was geographically adjacent to Sodom's site, reinforcing the connection.</p>",
    "10": "<p>'It will not be quenched night or day; its smoke will rise forever. From generation to generation it will lie desolate; no one will pass through it, forever and ever' — the permanent, unquenchable destruction: 'laylah veyyomam lo tichbeh, night and day it will not be quenched.' The self-sustaining fire of divine judgment — no natural cause can extinguish it. 'Its smoke will rise forever' (leolamim ya'aleh ashanah, her smoke will go up forever and ever) — eternal burning smoke. Rev 14:11 quotes this for the torment of those who worship the beast: 'the smoke of their torment goes up for ever and ever.' Rev 19:3 quotes it for the fall of Babylon: 'the smoke from her goes up for ever and ever.' The perpetual desolation: 'from generation to generation it will lie desolate' (ledor vador tishammah, from generation to generation it will be desolate) = the total absence of any resettlement or recovery, forever.</p>",
    "11": "<p>'The pelican and the porcupine will take possession of it; the owl and the raven will nest there. The LORD will stretch over it the measuring line of chaos and the plumb line of emptiness' — the wild-animal inventory of the desolate land: 'vireshuhah qa'at veqippod, the pelican and porcupine will possess it' (qa'at = the desert pelican or owl; qippod = the porcupine or short-eared owl). 'The owl and raven will nest there' (yanshuf ve'orev yishku vah, the owl and raven will dwell in her). But the theological climax: 'venathah aleyhah qav tohu ve'avnei vohu, he will stretch over her the measuring line of chaos and the plumb line of emptiness.' The qav tohu (measuring line of chaos) and avnei vohu (plumb line of emptiness) — the builder's measuring-line and plumb-stone (used to ensure accurate construction) here applied to anti-construction. The exact vocabulary of Gen 1:2 (tohu vavohu, chaos and void) applied to Edom's end: creation is being unmade by the same instruments by which it was made. YHWH the builder unmeasures Edom back into pre-creation chaos.</p>",
    "12": "<p>'They will call it, No Kingdom There, and all its princes will come to nothing' — the complete erasure of Edom's political structures: 'chorehav velo-sham malkut yiqre'u, its nobles — and no kingdom will be called there.' The chorehyah (its nobles/free-born = the aristocratic class, from chur = the white linen of the upper class) are stripped of status: 'no kingdom there' = the political entity of Edom simply ceases to exist as a recognizable kingdom. 'And all its princes will come to nothing' (vekol-sareyhah yihyu ayen, and all its princes will become nothingness). The sar (prince/official) reduced to ayin (nothing = the absolute non-being, the word used for non-existence). The double erasure: the kingdom-title gone, the individual officials reduced to nothing.</p>",
    "13": "<p>'Thorns will overgrow its citadels, nettles and brambles its fortresses; it will become a haunt for jackals, a dwelling place for ostriches' — the vegetation-and-wildlife takeover: 've'altah armenoteiha sirim, thorns will overgrow its citadels' (armenoteiha = its citadels/palaces). The sirim (thorns) and qimmosh (nettles/weeds) and chadah (brambles/thistles) — the judgment-vegetation (5:6; 7:23-25; 9:18; 10:17; 27:4; 32:13) overtaking the noble buildings. 'A haunt for jackals' (naveh tannim, a place of jackals/dragons) — the tannim (jackals/sea-monsters, used for both the desert-dwelling jackal and mythological dragons) in ruins is the standard desolation-image (Jer 9:11; 10:22; 49:33; 51:37). 'A dwelling place for ostriches' (chatsir livnot ya'anah, a courtyard for daughters of the owl/ostrich) — the wilderness bird that makes its nest in desolate places (Lam 4:3).</p>",
    "14": "<p>'Wildcats and hyenas will encounter each other there; the wild goat will call out to his fellow. The night owl will also settle there and find her resting place' — the continuation of the fauna inventory: 'upaggeshu tsiyim et-iyim, wildcats will encounter hyenas there.' The tsiyyim (desert creatures/wildcats = the denizens of desolate wastes, Ps 72:9; Isa 13:21) and iyyim (hyenas or howling creatures). 'The wild goat will call to his fellow' (vesair el-re'ehu yiqra, and the goat/satyr will call to his fellow) — the se'ir (the hairy/shaggy goat, but also the term for a goat-demon or satyr of ANE mythology, Lev 17:7: Israel must no longer offer sacrifices to the goat-demons). The demonic-goat's calling echoes the ANE understanding of ruins as the dwelling of demonic powers. 'The night owl' (lilit, the Lilith = the night-creature, related to layil = night; in later Jewish tradition Lilith became a female demon, the queen of the night) 'will settle there and find her resting place.'</p>",
    "15": "<p>'There the great owl will make her nest, lay eggs, hatch, and gather her young under her shadow; and the hawks will assemble there, each with its mate' — the breeding cycle of the wilderness fauna completing the desolation: 'sham qinnena qippoz vattefel vatevqa, there the great owl will make her nest and lay eggs and hatch.' The detailed nesting-and-breeding sequence (nest → eggs → hatching → gathering young) = the permanence of the wild animal occupation. Not a temporary passing-through but a multi-generational settlement: the birds are raising families in the ruins. 'The hawks will assemble there, each with its mate' (sham niqqebbetsu dayot ishah re'utah, the kites/hawks will assemble, each with her companion) — the hawks gathering in pairs = the beginning of new families in the ruins. The animal breeding cycles demonstrate that the desolation will persist for generations.</p>",
    "16": "<p>'Search and read the book of the LORD: not one of these will be absent, not one will lack its mate. For my mouth has issued the command, and his Spirit has gathered them' — the prophetic guarantee of fulfillment: 'dirshu missefer YHWH veqiru, search and read from the book of YHWH.' The 'book of the LORD' (sefer YHWH) may be the scroll of prophetic oracles (8:16-17; 30:8) or the divine book of decrees. The instruction to verify: none of the animals listed will be absent, none without their mate. 'Ki-pi hu tsivah verucho hikkibbetsam, for his mouth commanded it and his Spirit gathered them' — the two agents of fulfillment: divine speech (pi hu tsivah, his mouth commanded it = the creative word of Gen 1: 'God said...and it was so') and divine Spirit (rucho, his Spirit = the Spirit who hovered over creation in Gen 1:2 now gathering the animals to inhabit the de-created Edom). The Spirit who created gathers the animals to inhabit the un-creation.</p>",
    "17": "<p>'He has cast the lot for them, and his hand has divided it for them by the measuring line; they will possess it forever; from generation to generation they will dwell there' — the divine land-distribution to the animals: 'vehu hippil lahem goral, and he cast the lot for them.' The lot-casting (goral = the sacred lot used to divide the land among Israel's tribes in Josh 14:2; 18:6) — the same mechanism Israel used to divide Canaan is used to distribute Edom's land to wild animals. 'His hand has divided it for them by the measuring line' (umiddo chalekah lahem baqav, and by measuring line he divided it for them) — the same measuring line of v.11 (the qav tohu) = the instrument of judgment also serves as the land-distribution tool. 'They will possess it forever; from generation to generation they will dwell there' (le'olam yiresheet, they will possess forever) — the animals receive the same 'forever' land-promise that Israel received for Canaan (Gen 17:8; Lev 25:34).</p>"
  },
  "35": {
    "1": "<p>'The wilderness and the dry land will rejoice; the desert will exult and blossom like the crocus' — the opening of the great reversal-chapter: 'yesussum midbar vetsiyah, the wilderness and the dry land will rejoice.' The midbar (wilderness/desert = the unproductive, uninhabitable zone) and tsiyah (the parched/dry land) personified as rejoicing communities. The wilderness rejoices: the same root (sus = to exult) as the Deuteronomic blessing (Deut 28:63: 'just as it pleased the LORD to make you prosper and increase in number, so it will please him to ruin and destroy you') here reversed — YHWH takes pleasure in the wilderness-restoration. 'Blossom like the crocus' (veti-chach kachabatseleth, and blossom like the crocus/rose of Sharon) — the chabatseleth (the crocus or narcissus or autumn crocus) = the first flower of spring appearing in the desert after rain. Contrast with ch.34's desolation and with 33:9's withering landscapes.</p>",
    "2": "<p>'It will blossom with lavish abundance and rejoice with joy and singing. The glory of Lebanon will be given to it, the splendor of Carmel and Sharon; they will see the glory of the LORD, the majesty of our God' — the restoration of the withered landscapes (33:9): 'paroch tiffrach vegil, it will blossom fully and rejoice.' The three great landscape-symbols of fertility (33:9 had them withering): Lebanon (the cedar-forest glory), Carmel (the productive mountain-garden), Sharon (the coastal agricultural plain) — their kavod (glory) and hadar (splendor) transferred to the formerly barren desert. 'They will see the glory of the LORD' (hemmah yiru kevod YHWH, they — the people going through the restored wilderness — will see the glory of YHWH) and 'the majesty of our God' (hadar Elohenu, the splendor of our God). The landscape-glory is YHWH's glory manifested in creation's restoration.</p>",
    "3": "<p>'Strengthen the weak hands, and steady the shaking knees' — the command to encourage the discouraged community: 'chazzequu yadayim rafot, strengthen the weak hands.' The rafot yadaim (slack/hanging hands = the physical gesture of despair and defeat, 2 Sam 4:1; Ezek 7:17; Zeph 3:16) to be 'strengthened' (chazaq = to be strong, the same chazaq as YHWH's 'be strong and courageous' commands to Joshua in Deut 31:6-7, 23). 'Steady the shaking knees' (uvirkayim koshelot ammetsu, and the stumbling/tottering knees, make firm) — the knees that tremble in fear (Nah 2:10; Dan 5:6: Belshazzar's knees knocked together) are commanded to be made firm. The command is to the remaining faithful community: they are to encourage the discouraged, not merely await YHWH's action passively.</p>",
    "4": "<p>'Say to those whose hearts are gripped with fear: Be strong; do not be afraid! See — your God will come with vengeance, with divine recompense. He will come and save you' — the herald's announcement: 'imru lenimhare-lev chizqu al-tira'u, say to those who are fearful-of-heart: be strong, do not fear.' The nihmere-lev (the anxious/hasty-of-heart = those whose hearts are in a state of panicked rush) addressed with the covenant comfort-formula 'do not be afraid' (al-tira'u) that appears throughout the patriarchal narratives (Gen 15:1; 26:24; 46:3) and Isaiah (7:4; 40:9; 41:10-14; 43:1-5). 'Your God will come with vengeance' (hineh Eloheikhem, naqam yavo, behold your God — vengeance will come) and 'divine recompense' (gemul Elohim = the recompense/retribution of God). 'He will come and save you' (hu yavo veyoshi'akhem, he will come and save you) — the definitive salvific coming.</p>",
    "5": "<p>'Then the eyes of the blind will be opened, and the ears of the deaf will be unstopped' — the four physical-healing signs of the messianic era: 'az tippaqachna einei ivre'im, then will be opened the eyes of the blind.' The tippaqachna (will be opened = from paqach = to open the eyes, specifically used for the opening of blind eyes, Gen 21:19: God 'opened her eyes' at Hagar's crisis; 2 Kgs 6:17-20: Elisha praying 'open his eyes'). 'The ears of the deaf will be unstopped' (ve'ozne cherashim tipatachnah, and the ears of the deaf will be opened) — patach (to open) applied to ears. These healings reverse the sealing/closing of 29:10-12 (spirit of deep sleep, eyes shut, ears covered) and 6:9-10 (the people who hear but do not understand, see but do not perceive). Jesus cites this exact verse (with v.6) in Matt 11:5 as proof of messianic presence to John the Baptist's disciples.</p>",
    "6": "<p>'Then the lame will leap like a deer, and the tongue of the mute will burst into song. For waters will break out in the wilderness and streams flow through the desert' — the healing extending to limbs and speech: 'az yedallleg kaayyal pisseyach, then the lame will leap like a deer.' The pisseyach (lame/limping = from passach, related to Passover, from the 'limping' at the threshold; 1 Kgs 18:21: Elijah's challenge about 'limping between two opinions'). The deer-leap (dallleg from dalag = to leap/spring, Song 2:8: 'leaping across the mountains, bounding over the hills') = the most agile, joyful movement. 'The tongue of the mute will burst into song' (velashon illem terannen, and the tongue of the mute will shout for joy) — the illem (the speechless/mute, from alam = to bind/silence). Waters in the wilderness (v.6b-7): the dual healing of human bodies and the physical landscape. Acts 8:39 (the Ethiopian eunuch going on his way rejoicing) and Acts 3:8 (the lame man leaping) fulfill the specific imagery.</p>",
    "7": "<p>'The burning sand will become a pool, and the thirsty ground springs of water; in the haunt of jackals, where they once rested, the grass will grow with reeds and rushes' — the ecological transformation of the desert: 'vehayah hashharav le'agam, and the burning sand will become a lake/pool.' The sharav (the mirage/burning sand of the desert = the shimmering heat-haze that looks like water but is not, the deceptive mirage) becomes an actual agam (a standing lake). 'The thirsty ground springs of water' (vetsimaon lemabbu'e mayim, and the thirsty/parched ground springs of water) = the parched cracked earth of the desert floor becomes a spring-source. 'In the haunt of jackals, where they once rested, the grass will grow with reeds and rushes' (binveh tannim ravtsah, in the dwelling of jackals, their resting-place, will be grass with reed and rush) — the 34:13's 'haunt of jackals' (the desolate ruin) is now transformed into a wetland where grass, reeds, and rushes grow.</p>",
    "8": "<p>'And a highway will be there, called the Way of Holiness; the unclean will not travel over it. It is for those who walk the road; even fools will not lose their way on it' — the Way of Holiness: 'vehayah sham maslul vaderekh, and a highway will be there, and a road.' The maslul (raised highway/paved road, the same root as mesillah = the main road) = a public infrastructure project in the desert. 'Called the Way of Holiness' (derekh haqodesh yiqqare' lah, the Way of Holiness will it be called) — qodesh (holiness) defines the road: not merely a physical highway but a sacred processional route. 'The unclean will not travel over it' (lo ya'averennah tame, the unclean will not pass over it) — the purity requirement for travel. 'Even fools will not lose their way on it' (ve'eviliym lo yit'u, and fools will not wander) — the Way of Holiness is so clearly marked that even the spiritually unsophisticated can follow it without getting lost. The Way theology anticipates John 14:6 ('I am the way').</p>",
    "9": "<p>'No lion will be there, nor will any ravenous beast be found on it. But the redeemed will walk there' — the safety of the Way of Holiness: 'lo-yihyeh sham aryeh, no lion will be there.' The lion (aryeh) = the apex predator of the ANE wilderness, the danger that made travel on ancient roads hazardous. 'Nor will any ravenous beast be found on it' (vepharits chayot bal-ya'alennah, and no savage wild animal will ascend onto it) — the predator-free sacred road. The contrasting population: 'vehalekhu gealim, but the redeemed will walk' (gealim = the redeemed = those YHWH has redeemed/bought back, from ga'al = the kinsman-redeemer who buys back a family member from slavery: Lev 25:25-54). The redeemed walking where lions dare not tread = the total reversal of wilderness danger. Isa 11:6-9 describes the peaceable kingdom where the lion lies down with the lamb.</p>",
    "10": "<p>'The ransomed of the LORD will return; they will come to Zion with singing, with everlasting joy on their heads. They will reach gladness and joy, and sorrow and sighing will flee away' — the climax of the restoration: 'ufeduyey YHWH yeshuevun, and the ransomed of YHWH will return.' The feduyey (ransomed = from padah = to redeem by payment, the commercial redemption that pays the price, vs. ga'al = the family redemption of v.9). The two redemption words together: gealim (v.9, family redemption) and feduyey (v.10, purchase redemption) = the comprehensive redemption language. 'They will come to Zion with singing' (uvau Tsiyon berinah, and they will come to Zion with ringing joy) — the processional arrival at Zion of the exiles returning. 'Everlasting joy on their heads' (simchat olam al-rosham, everlasting joy upon their heads) = the festive garland of joy replacing the ash of mourning (61:3). 'Sorrow and sighing will flee away' (venassu yagon va'anachah, and sorrow and sighing will flee) — quoted in Rev 21:4 alongside the 'no more death, mourning, crying, pain.'</p>"
  },
  "36": {
    "1": "<p>Isaiah 36 begins the 'Historical Appendix' (chs. 36-39) that largely parallels 2 Kings 18:13-20:19. This historical narrative provides the concrete crisis that all the preceding oracles (particularly chs. 28-35) were responding to: the Assyrian invasion of Sennacherib in 701 BCE. 'Vayehi bearba esreh shanah lamelekh Chizkiyahu, and it was in the fourteenth year of King Hezekiah.' The fourteenth year of Hezekiah = 701 BCE by standard chronology, the third campaign of Sennacherib (705-681 BCE). Sennacherib's own annals (the Taylor Prism in the British Museum) confirm: 'I besieged and conquered 46 fortified cities of Judah... Hezekiah himself I shut up like a caged bird in Jerusalem his royal city.' 'He marched against all the fortified cities of Judah and captured them' — the Lachish letters and archaeological evidence confirm the systematic capture of Judean cities before Jerusalem.</p>",
    "2": "<p>'Then the king of Assyria sent his field commander Rabshakeh from Lachish to King Hezekiah in Jerusalem with a large army' — the Rabshakeh (rāb šāqê = the 'chief cup-bearer' title, but actually a senior diplomatic-military official in the Assyrian court hierarchy, attested in multiple Assyrian documents). From Lachish: Lachish (Tel Lachish, modern Tell ed-Duweir, 30 miles southwest of Jerusalem) was the second most important city of Judah. Sennacherib's siege of Lachish is depicted in extraordinary detail in the Lachish Reliefs (Southwest Palace of Nineveh, now in the British Museum) — 8 carved stone panels showing the siege ramps, battering rams, and the capture and deportation of the population. 'He took up a position at the channel of the upper pool, on the road to the Washerman's Field' — the exact same location as Isa 7:3 (where Isaiah met Ahaz during the Syro-Ephraimite crisis of 735 BCE). The topographic connection underscores the parallel: two Assyrian crises, same location, same prophetic word of trust in YHWH.</p>",
    "3": "<p>'Then Eliakim son of Hilkiah, the palace administrator, came out to meet him, along with Shebna the secretary and Joah son of Asaph, the recorder' — the three Judean officials: (1) Eliakim son of Hilkiah (hakkaykim ben-chilqiyahu asher al-habbayit) = the palace administrator/steward, the highest civil office in the royal household. Isa 22:20-25 contains YHWH's oracle specifically concerning Eliakim: 'I will call my servant Eliakim son of Hilkiah... I will clothe him with your robe and fasten your sash and hand your authority over to him' — Eliakim is YHWH's appointed replacement for the corrupt Shebna. (2) Shebna the secretary (shebna hassoferyh) — in 22:15-19 YHWH had specifically prophesied Shebna's downfall: 'What are you doing here... I am going to hurl you away forcefully, O mighty man, and grasp you firmly.' He has now been demoted from palace administrator to secretary. (3) Joah son of Asaph, the recorder (hamazkirm) = the court historian/chronicler.</p>",
    "4": "<p>'Rabshakeh said to them, Tell Hezekiah: This is what the great king, the king of Assyria, says — What is this confidence you are trusting in?' — the opening of Rabshakeh's rhetorical assault. The diplomatic formula 'this is what the great king, the king of Assyria says' (ko-amar hammelek hagadol melek Ashshur) = the suzerainty treaty opening formula, with Sennacherib's full royal title (hamelekh hagedol = the Great King was the specific Assyrian imperial title used in their royal inscriptions and treaties). The first rhetorical question: 'mah ha'emunah hazot asher batacht, what is this trust which you are trusting?' — batach (trust = the covenant-trust word that runs through the whole oracle-series; 30:12, 15; 31:1 have all condemned misplaced trust). Now Rabshakeh uses the same language: what is the basis of Hezekiah's confidence?</p>",
    "5": "<p>'I tell you — mere words are not strategy or battle strength. So whom do you rely on, that you have dared to rebel against me?' — the military-strategic analysis: 'amarti akh-davar sefatayim etsah ugevurah lamilchamah, I say — surely a word of the lips is counsel and strength for battle?' The sarcastic rhetorical question: 'are you counting on a word of the lips (mere talk) for military strategy?' — contrasting diplomatic promises with actual military capability. 'On whom do you rely, that you have rebelled against me?' (al mi batacht ki maradtah bi, on whom have you trusted that you have rebelled against me?) — the political analysis: Hezekiah's refusal to pay tribute (which the Assyrian records call 'rebellion') must have been based on some strategic calculation. Rabshakeh demands: what or who is that calculation?</p>",
    "6": "<p>'Look — you are leaning on Egypt, that cracked and broken reed of a staff. If anyone leans on it, it pierces right through his hand. That is what Pharaoh king of Egypt is to anyone who trusts him' — the Egypt-as-broken-reed assessment: 'hineh batacht al-mishe'en haqaneh hara-tsuts hazzeh, behold you are trusting on the staff of this crushed reed.' The qaneh (reed = the Nile reed used to make walking-sticks and writing pens, plentiful in Egypt; qaneh/kaneh = the reed-staff) that is rasuts (crushed/cracked = structurally compromised, unable to bear weight). Remarkably, Rabshakeh uses the same metaphor for Egypt that Isaiah himself had used in 30:6 and 31:1-3! Either (a) Isaiah's prophecies had become widely known, (b) the 'broken reed' was a common ANE proverb for Egyptian unreliability, or (c) the Assyrian military intelligence had absorbed Judean prophetic discourse. 'It pierces right through his hand' (uba bechafpo uvaqavah yaddo, and it enters into his palm and pierces his hand) — the staff that should support becomes a weapon against its user.</p>",
    "7": "<p>'But if you say to me, We trust in the LORD our God, isn't this the very God whose high places and altars Hezekiah removed, telling Judah and Jerusalem, You must worship at this one altar?' — Rabshakeh's deliberate misrepresentation of Hezekiah's reform: 've'im-tomar elai el-YHWH Elohenu batachnu, and if you say to me, In the LORD our God we trust.' Hezekiah's religious reform (2 Kgs 18:3-6) had centralized worship in Jerusalem by destroying the high places (bamot) and altars throughout Judah. From an Assyrian perspective (and from those Judeans who valued the local shrines), this looked like Hezekiah had reduced YHWH's worship-sites. Rabshakeh's argument: by removing most of the places where people could worship YHWH, Hezekiah has actually weakened the deity's position. The argument is theologically absurd (YHWH is not diminished by fewer shrines) but rhetorically clever — it exploits the Judeans' folk-theology that more shrines = more divine power.</p>",
    "8": "<p>'Come now — make a wager with my master the king of Assyria: I will give you two thousand horses, if you can actually find riders to put on them' — the military-capability challenge: 'hitarev na et-adoni hammelek Ashshur ve'ettenah lekha alpayim susim, make a wager/exchange with my lord the king of Assyria and I will give you 2,000 horses.' The offer is designed to humiliate: Judah is so lacking in trained cavalry that they couldn't even mount 2,000 horses if given them. This is precisely the concern of 30:16-17 (trusting in swift horses) and 31:1 (trusting in chariots and cavalry) — Isaiah had warned against Egypt's cavalry, and Rabshakeh now exposes the gap: you don't have cavalry of your own either. Sennacherib's annals describe the Assyrian army's deployment of vast chariot forces — the contrast with Judah's minimal cavalry would have been obvious.</p>",
    "9": "<p>'How then could you hold off even one of the least of my master's junior officers? Yet here you are, trusting Egypt for chariots and horsemen!' — the cascading military impossibility: 've'eikh tashuv et-penei pechath echad avadei adoni haqqetannim, and how will you turn back the face of one prefect of the least of my lord's servants?' The pechath (governor/prefect = a mid-level Assyrian administrative-military officer, not even a general) would be too much for Jerusalem's army. 'Yet here you are, trusting Egypt for chariots and horsemen' (vatibetach lekha al-Mitsrayim lerakhev ulepharashim, and you have trusted to yourself in Egypt for chariots and horsemen) — the Judean strategy exposed as both inadequate (they can't even mount 2,000 horses if given) and misplaced (Egypt couldn't help anyway, as chs. 30-31 warned).</p>",
    "10": "<p>'And do you think I have come up against this land without the LORD's approval? The LORD himself said to me: March against this land and destroy it' — the most theologically significant claim in Rabshakeh's speech: 'ha'min bilti YHWH aliythi al-ha'arets hazot leshachitah, was it apart from YHWH that I came up against this land to destroy it?' The claim that YHWH commissioned the Assyrian invasion echoes Isaiah's own oracles: 10:5-6 ('Woe to Assyria, the rod of my anger, in whose hand is the club of my wrath; I send him against a godless nation'); 36:10 and 10:5-6 are in direct dialogue. Whether Rabshakeh genuinely believed YHWH had spoken (a plausible claim in ANE theological logic where conquered peoples's gods were seen as abandoning them) or was cynically manipulating Judean theology, the claim had prophetic backing that Hezekiah could not simply dismiss.</p>",
    "11": "<p>'Please speak to us your servants in Aramaic, for we understand it. Do not speak Hebrew in the hearing of the people who are on the wall' — the linguistic-diplomatic request: 'dabber-na el-avadekhah Aramit ki shome'iyn anachnu, please speak to your servants in Aramaic for we understand.' Aramaic (Aramit) was the diplomatic lingua franca of the ANE by the 8th century BCE — attested in Assyrian royal inscriptions as the language of international communication (like English today). The Judean officials understood Aramaic (as educated diplomats would). Hebrew (Yehudit = literally 'Judean,' the regional vernacular) was the language of the common people (the soldiers on the wall, the civilian population). The officials' request: conduct the negotiations in diplomatic language to prevent a public-relations disaster. Rabshakeh's refusal (v.12) is deliberate — he wants the population to hear and panic, bypassing the leadership to address the rank-and-file directly.</p>",
    "12": "<p>'Did my master send me to speak these words only to your master and to you? Was he not also sending a message to the men on the wall — who will end up eating their own filth and drinking their own urine alongside you when the siege is over?' — the psychological warfare of direct address to the soldiers: 'ha'al adonekha ve'eleykha shalachani adoni, was it to your lord and to you that my lord sent me?' Rabshakeh deliberately bypasses the diplomatic hierarchy to address the common soldier. The siege-threat: 'le'akhol et-tso'atam velishto et-shineyhem imakem, to eat their dung and drink their urine with you' — the most extreme conditions of starvation-siege: 2 Kgs 6:25-29 describes Samaria's siege under Ben-Hadad where donkey's heads sold for 80 shekels and dove's dung for 5 shekels of silver, and even cannibalism occurred. Sennacherib's threat: if you endure the siege, this is what happens. The graphic language is designed to terrify the soldiers into pressuring Hezekiah to surrender.</p>",
    "13": "<p>'Then Rabshakeh stood up and shouted in Hebrew at full volume: Hear the words of the great king, the king of Assyria!' — the public-address pivot: 'vayya'amod Ravshaqeh vayiqra beqol gadol Yehudit, and Rabshakeh stood up and called out in a loud voice in Hebrew/Judean.' Rabshakeh physically stands (the posture of the herald making a public proclamation) and 'calls out' (yiqra = the public herald's proclamation, cf. Isa 40:3: 'a voice crying out in the wilderness'). 'In a loud voice in Hebrew' — the diplomatic lingua franca abandoned; Rabshakeh speaks the people's own language. The 'great king' (hammelek hagadol) formula again — Sennacherib's imperial title used in his own inscriptions as hamelekh harabbu (the Great King). The direct appeal to the people over the heads of their leaders is a sophisticated psychological operation.</p>",
    "14": "<p>'This is the king's word: Do not let Hezekiah mislead you — he is not able to deliver you' — the direct undermining of Hezekiah's authority: 'ko-amar hammelek al-yashia lakhem Chizkiyahu, thus says the king: do not let Hezekiah lead you into folly.' Al-yashia (do not let him lead you astray/save you) — yashia from nasha (to lead astray/deceive) = Rabshakeh frames Hezekiah's defiance as deception of his own people. 'He is not able to deliver you' (lo-yukhal lehatssilekhem, he is not able to rescue/deliver you) — the same verb that Rabshakeh will use in vv.18-20 for the inability of other gods to deliver. By framing Hezekiah's advocacy for trust in YHWH as deception, Rabshakeh attempts to separate the king from his people's confidence in his leadership.</p>",
    "15": "<p>'And do not let Hezekiah lead you to trust in the LORD by saying, The LORD will certainly deliver us — this city will not fall into the king of Assyria's hands' — Rabshakeh directly attacks the prophetic promise: 'veal-yavtech etkhem Chizkiyahu el-YHWH, and do not let Hezekiah lead you to trust in YHWH.' The target: the specific prophetic promise that Isaiah had been delivering throughout the Assyrian crisis — that YHWH would defend Jerusalem (37:33-35 confirms this promise was given). 'The LORD will certainly deliver us' (hatstsil yatssilenu YHWH, YHWH will surely deliver us) — the double verb (absolute infinitive + finite verb) = emphatic certainty. Hezekiah had been relying on this promise. Rabshakeh's strategy: if he can get the Judeans to doubt the prophetic promise, Hezekiah's resistance collapses without a siege.</p>",
    "16": "<p>'Do not listen to Hezekiah. For this is what the king of Assyria says: Make terms with me and surrender — and every one of you will eat from his own vine and his own fig tree and drink from his own cistern' — the counter-offer of peace: 'al-tishme'u el-Chizkiyahu, do not listen to Hezekiah.' The alternative to Hezekiah's resistance: 'asu itti berakhah, make a blessing/terms with me' (the euphemism for surrender — berakhah = a blessing/gift = the terms of a peaceful capitulation). The promised conditions: 'each man eating from his own vine and fig tree' (ish gepenno ve'ish te'enato, each man his vine and each man his fig tree) = the Solomonic peace-formula of 1 Kgs 4:25 ('during Solomon's lifetime Judah and Israel lived in safety, each man under his own vine and fig tree'). Rabshakeh offers to restore the conditions of the golden age — but as Assyrian subjects. 'Drink from his own cistern' (veshatu ish mei-bor, and drink each man water of his cistern) = the domestic water supply undisturbed.</p>",
    "17": "<p>'Until I come and take you to a land just like your own — a land of grain and new wine, a land of bread and vineyards' — the deportation promise dressed as opportunity: 'ad-ba'i velaqachti etkhem, until I come and take you.' The transparent admission: the peace terms include eventual deportation to 'a land just like your own' (el-erets ketartsekhem, a land like your own land) = 'a land of grain and new wine' (erets dagan vetirosh, a land of grain and wine). The offer is essentially the Assyrian resettlement policy: conquered populations were deported to other parts of the empire and replaced with other deportees. Rabshakeh frames this as a positive: the new land is 'just like yours.' This is historically accurate — Assyrian resettlement policy often placed conquered peoples in comparably productive agricultural regions. But the offer is a velvet-gloved deportation threat.</p>",
    "18": "<p>'Watch out — do not let Hezekiah deceive you by saying, The LORD will deliver us. Has any god of the nations ever delivered his land from the power of the king of Assyria?' — the comparative-religion challenge: 'pen-yassit etkhem Chizkiyahu, do not let Hezekiah mislead/entice you.' The final theological argument — and the most powerful: 'hehitsil elohei hagoyim ish arto miyyad melek Ashshur, has any god of the nations delivered his land from the hand of the king of Assyria?' The Assyrian track record: no god of any conquered nation had successfully defended his people against Assyrian conquest. This is historically accurate as Assyrian propaganda — the Assyrian campaign records consistently portray the conquest of cities as the abandonment or defeat of their patron deities. The Assyrian theology: Ashur is greater than all other gods, demonstrated by military conquest. YHWH is just one more local deity who will fail like the rest.</p>",
    "19": "<p>'Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? Did they deliver Samaria from my power?' — the list of defeated deities: 'ayeh elohei Chamat ve'Arpad, where are the gods of Hamath and Arpad?' Hamath (modern Hama on the Orontes River in Syria, conquered by Sargon II in 720 BCE). Arpad (modern Tell Rif'at north of Aleppo, conquered by Tiglath-pileser III in 740 BCE and by Sargon II). Sepharvaim (possibly Sibraim between Damascus and Hamath, or the Babylonian Sippar — conquered by Sargon II). Samaria (the capital of the northern Kingdom of Israel, conquered by Sargon II in 722 BCE after a 3-year siege) — the most pointed example: YHWH's own people, the northern kingdom, with their presumably YHWH-related cult, could not resist the Assyrians. The logic: if YHWH didn't save his own people in Samaria, why would he save Jerusalem?</p>",
    "20": "<p>'Which of all the gods of these lands has ever delivered his land from my power? What makes you think the LORD will deliver Jerusalem from me?' — the climactic rhetorical question: 'mi bekhol elohei ha'aratsot ha'elleh asher hitsilu et-artsam miyyadi, who among all the gods of these lands delivered his land from my hand?' The rhetorical force: the cumulative record of divine failure across the region creates an overwhelming case. 'What makes you think the LORD will deliver Jerusalem from me?' (ki-yatsil YHWH et-Yerushalayim miyyadi, that YHWH will deliver Jerusalem from my hand?) — the final pointed application. The argument works on Assyrian theological premises but not on covenantal ones: YHWH is not merely a local patron deity but the creator of all things, the one who uses Assyria itself as his instrument (10:5). Rabshakeh's theology is sophisticated but ultimately ignores Israel's particular covenant claim.</p>",
    "21": "<p>'But they remained silent and said nothing in reply, for the king had commanded, Do not answer him' — the strategic silence: 'vayecherieshu velo-anuhv oto dabar, and they kept silent and did not answer him a word.' The Judean officials' silence is the only appropriate response given the king's command. To answer Rabshakeh's theological challenges would be to engage the enemy's framing on his terms — acknowledging that YHWH's power is in question. The silence is both obedience to Hezekiah's command and a refusal to dignify the comparison of YHWH with the gods of the nations. The theological truth is that YHWH is not comparable to Hamath's gods — but Rabshakeh's framework does not admit this. Silence preserves the distinction. Jesus's silence before Pilate (Matt 27:14; Mark 15:5; Isa 53:7: 'he was led like a sheep to the slaughter... he did not open his mouth') echoes the same dynamic.</p>",
    "22": "<p>'Then Eliakim son of Hilkiah, the palace administrator, Shebna the secretary, and Joah son of Asaph, the recorder, came to Hezekiah with their robes torn and reported to him what Rabshakeh had said' — the report to Hezekiah: the three officials return with their garments torn. 'They came to Hezekiah begihadim qeruyim, with torn garments' — qara (to tear, to rend) is the physical mourning-and-distress gesture (Gen 37:29: Reuben tore his clothes on finding Joseph gone; 2 Sam 13:31: David tore his clothes at Amnon's sin; 2 Kgs 22:11: Josiah tore his clothes when the Book of the Law was read; Ezra 9:3). The torn robes signal that the Rabshakeh's speech has hit its mark — the officials are in genuine distress. Their report to Hezekiah ('they told him the words of Rabshakeh') sets up ch.37's climax: Hezekiah's prayer, Isaiah's oracle, and YHWH's dramatic deliverance in the night.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
